#include <string>

std::string markdown_to_html(std::string& markdown) {
  std::string html;

  // Use a regular expression to find all headers in the markdown and convert them to HTML headings
  std::string heading_re = "^#( *)([^ ]*)";
  size_t match_start = markdown.find(heading_re);
  while (match_start != std::string::npos) {
    size_t match_end = match_start + heading_re.length();
    std::string heading_level = match_start == 0 ? "h1" : (match_start == 1 ? "h2" : (match_start == 2 ? "h3" : (match_start == 3 ? "h4" : "h5")));
    html += "<" + heading_level + ">";
    html += markdown.substr(match_start + 1, match_end - match_start - 1);
    html += "</" + heading_level + ">";
    match_start = markdown.find(heading_re, match_end);
  }

  // Remove the headers from the markdown
  markdown.erase(markdown.find_first_not_of(' '));

  // Use a regular expression to find all bold and italic text in the markdown and convert it to HTML bold and italic tags
  std::string bold_italic_re = "^([^ ]*)([*][^ ]*)([^ ]*)";
  std::string bold_re = "^([^ ]*)([*][^ ]*)";
  std::string italic_re = "^([^ ]*)([_][^ ]*)";
  std::string text;
  size_t start = 0;
  while ((match_start = markdown.find(bold_italic_re, start)) != std::string::npos) {
    size_t match_end = match_start + bold_italic_re.length();
    text = markdown.substr(match_start, match_end - match_start);
    if (text.compare(0, 1, "*") == 0) {
      html += "<strong>";
    } else if (text.compare(0, 1, "_") == 0) {
      html += "<em>";
    }
    html += text;
    html += "</strong>";
    html += "</em>";
    start = match_end;
  }
  start = 0;
  while ((match_start = markdown.find(bold_re, start)) != std::string::npos) {
    size_t match_end = match_start + bold_re.length();
    text = markdown.substr(match_start, match_end - match_start);
    html += "<strong>";
    html += text;
    html += "</strong>";
    start = match_end;
  }
  start = 0;
  while ((match_start = markdown.find(italic_re, start)) != std::string::npos) {
    size_t match_end = match_start + italic_re.length();
    text = markdown.substr(match_start, match_end - match_start);
    html += "<em>";
    html += text;
    html += "</em>";
    start = match_end;
  }

  // Add the rest of the markdown as a paragraph
  html += "<p>";
  html += markdown;
  html += "</p>";

  return html;
}
```
This function first finds all the headers in the markdown and converts them to HTML headings. It then removes the headers from the markdown. It then finds all the bold and italic text in the markdown and converts it to HTML bold and italic tags. Finally, it adds the rest of the markdown as a paragraph.

